"""
Step ID: step02
Step Name: standardize_scores
RQ: results/ch7/7.7.4
Generated: 2026-01-09

PURPOSE:
Convert RAVLT and REMEMVR scores to z-scores for fair comparison across tests
with different scales. Z-score standardization enables classification using
common thresholds (e.g., z < -1.0 = impaired, z > -0.5 = normal).

EXPECTED INPUTS:
  - results/ch7/7.7.4/data/step01_cognitive_scores.csv
    Columns: ['UID', 'REMEMVR_theta', 'RAVLT_Total']
    Format: Merged cognitive scores for standardization
    Expected rows: 100 participants

EXPECTED OUTPUTS:
  - results/ch7/7.7.4/data/step02_standardized_scores.csv
    Columns: ['UID', 'REMEMVR_theta', 'RAVLT_Total', 'RAVLT_z', 'REMEMVR_z',
              'Age', 'Education', 'VR_Experience', 'NART_Score']
    Format: Cognitive scores with z-score standardization for classification
    Expected rows: 100 participants

VALIDATION CRITERIA:
  - RAVLT_z mean ≈ 0.0 (within 0.01)
  - RAVLT_z std ≈ 1.0 (within 0.01)
  - REMEMVR_z mean ≈ 0.0 (within 0.01)
  - REMEMVR_z std ≈ 1.0 (within 0.01)
  - No missing z-scores

g_code REASONING:
- Approach: Apply scipy.stats.zscore to RAVLT_Total and REMEMVR_theta
- Why this approach: Standard z-score formula (x - mean) / std ensures comparability
- Data flow: Raw scores → z-score transformation → validated standardization
- Expected performance: <2 seconds

IMPLEMENTATION NOTES:
- Analysis tool: scipy.stats.zscore (standard library function)
- Validation tool: validate_standardization from tools.validation
- Parameters: nan_policy='omit' to handle any missing values gracefully
- Note: REMEMVR_theta already approximately standardized (IRT scale), but re-standardizing
  ensures identical scale properties for fair classification thresholds
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
from scipy.stats import zscore
from typing import Dict, List, Any
import traceback

# Add project root to path for imports
PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

# Import validation tool
from tools.validation import validate_standardization

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]  # results/ch7/7.7.4
LOG_FILE = RQ_DIR / "logs" / "step02_standardize_scores.log"
INPUT_FILE = RQ_DIR / "data" / "step01_cognitive_scores.csv"
OUTPUT_FILE = RQ_DIR / "data" / "step02_standardized_scores.csv"

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 02: standardize_scores")

        # =========================================================================
        # STEP 1: Load Cognitive Scores
        # =========================================================================
        log("[LOAD] Loading cognitive scores from step01...")

        df = pd.read_csv(INPUT_FILE)
        log(f"[LOADED] {INPUT_FILE} ({len(df)} rows, {len(df.columns)} columns)")

        # =========================================================================
        # STEP 2: Compute Z-Scores
        # =========================================================================
        log("[ANALYSIS] Computing z-scores for RAVLT and REMEMVR...")

        # Z-score for RAVLT_Total
        # nan_policy='omit' excludes NaN from calculation but preserves them in output
        df['RAVLT_z'] = zscore(df['RAVLT_Total'], axis=0, nan_policy='omit')
        log(f"[COMPUTED] RAVLT_z: mean={df['RAVLT_z'].mean():.6f}, std={df['RAVLT_z'].std():.6f}")

        # Z-score for REMEMVR_theta
        # Note: REMEMVR_theta already approximately standardized (IRT scale ~N(0,1))
        # but re-standardizing ensures identical properties for classification
        df['REMEMVR_z'] = zscore(df['REMEMVR_theta'], axis=0, nan_policy='omit')
        log(f"[COMPUTED] REMEMVR_z: mean={df['REMEMVR_z'].mean():.6f}, std={df['REMEMVR_z'].std():.6f}")

        # Z-score for RAVLT_Pct_Ret (percent retention)
        df['RAVLT_Pct_Ret_z'] = zscore(df['RAVLT_Pct_Ret'], axis=0, nan_policy='omit')
        log(f"[COMPUTED] RAVLT_Pct_Ret_z: mean={df['RAVLT_Pct_Ret_z'].mean():.6f}, std={df['RAVLT_Pct_Ret_z'].std():.6f}")

        # Check for any missing z-scores
        missing_ravlt_z = df['RAVLT_z'].isnull().sum()
        missing_rememvr_z = df['REMEMVR_z'].isnull().sum()
        missing_pct_ret_z = df['RAVLT_Pct_Ret_z'].isnull().sum()

        if missing_ravlt_z > 0:
            log(f"[WARN] {missing_ravlt_z} participants missing RAVLT_z scores")
        if missing_rememvr_z > 0:
            log(f"[WARN] {missing_rememvr_z} participants missing REMEMVR_z scores")
        if missing_pct_ret_z > 0:
            log(f"[WARN] {missing_pct_ret_z} participants missing RAVLT_Pct_Ret_z scores")

        if missing_ravlt_z == 0 and missing_rememvr_z == 0 and missing_pct_ret_z == 0:
            log(f"[PASS] No missing z-scores")

        # =========================================================================
        # STEP 3: Save Standardized Scores
        # =========================================================================
        log("[SAVE] Saving standardized scores...")

        df.to_csv(OUTPUT_FILE, index=False, encoding='utf-8')
        log(f"[SAVED] {OUTPUT_FILE} ({len(df)} rows, {len(df.columns)} columns)")

        # =========================================================================
        # STEP 4: Validate Standardization
        # =========================================================================
        log("[VALIDATION] Running validate_standardization...")

        check_columns = ['RAVLT_z', 'REMEMVR_z', 'RAVLT_Pct_Ret_z']
        validation_result = validate_standardization(
            df=df,
            column_names=check_columns,
            tolerance=0.01
        )

        if validation_result.get('valid', False):
            log(f"[PASS] Standardization validation passed")

            # Report detailed statistics
            for col in check_columns:
                mean_val = df[col].mean()
                std_val = df[col].std()
                min_val = df[col].min()
                max_val = df[col].max()
                log(f"[INFO] {col}: mean={mean_val:.6f}, std={std_val:.6f}, range=[{min_val:.3f}, {max_val:.3f}]")
        else:
            log(f"[FAIL] Standardization validation failed: {validation_result.get('message', 'Unknown error')}")
            raise ValueError(f"Standardization validation failed: {validation_result}")

        # Additional manual checks (for transparency)
        log("[VALIDATION] Manual standardization checks...")

        for col in check_columns:
            mean_val = df[col].mean()
            std_val = df[col].std(ddof=0)  # Population std (same as scipy.stats.zscore uses)

            # Check mean ≈ 0
            if abs(mean_val) > 0.01:
                log(f"[WARN] {col} mean={mean_val:.6f} deviates from 0.0 (tolerance=0.01)")
            else:
                log(f"[PASS] {col} mean={mean_val:.6f} within tolerance")

            # Check std ≈ 1
            if abs(std_val - 1.0) > 0.01:
                log(f"[WARN] {col} std={std_val:.6f} deviates from 1.0 (tolerance=0.01)")
            else:
                log(f"[PASS] {col} std={std_val:.6f} within tolerance")

        log("[SUCCESS] Step 02 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
